UPDATE public.us_cities_scored u
SET private_elementary_count = src.n,
    nces_last_updated = CURRENT_DATE
FROM (SELECT * FROM pss UNION ALL SELECT * FROM pss2) src
WHERE UPPER(u.city_name) = src.city AND u.state_abbr = src.st;

-- Provenance: write a city_market_signals row for each updated city
INSERT INTO public.city_market_signals (city_id, signal_key, label, value, source, confidence, updated_at)
SELECT u.id, 'private_elementary_count', 'Private elementary schools (NCES PSS)',
       u.private_elementary_count::text, 'NCES PSS 2021-22', 0.90, now()
FROM public.us_cities_scored u
WHERE u.private_elementary_count IS NOT NULL
  AND u.nces_last_updated = CURRENT_DATE
ON CONFLICT (city_id, signal_key)
DO UPDATE SET value = EXCLUDED.value, source = EXCLUDED.source,
              confidence = EXCLUDED.confidence, updated_at = now();